def get_reward_cfg(env_cfg, robot_ee_body_name: str):
    """
    This function is called by reach_task.py to inject 
    the generated rewards into the Environment Config.
    """
    
    # We define the specific rewards here based on what the LLM created.
    # The LLM will be instructed to provide a dictionary called 'generated_terms'
    
    reward_dict = {
    "ee_reach": RewTerm(func=ee_reach_reward, weight=1.0, params={"asset_cfg": SceneEntityCfg("franka", body_names=["panda_hand"]), "command_name": "ee_pose"}),
    "ee_orientation": RewTerm(func=ee_orientation_reward, weight=0.5, params={"asset_cfg": SceneEntityCfg("franka", body_names=["panda_hand"]), "command_name": "ee_pose"}),
    "action_rate": RewTerm(func=action_rate_penalty, weight=0.01, params={"asset_cfg": SceneEntityCfg("franka", body_names=["panda_hand"])}),
    "reach_success": RewTerm(func=success_metric, weight=10.0, params={"asset_cfg": SceneEntityCfg("franka", body_names=["panda_hand"]), "command_name": "ee_pose"}),
}
    
    # Example of what the LLM should generate:
    # reward_dict = {
    #     "reaching_goal": RewTerm(
    #         func=rew_function_name, # One of the functions inserted above
    #         weight=1.0,
    #         params={"asset_cfg": SceneEntityCfg("robot", body_names=[robot_ee_body_name]), "command_name": "ee_pose"}
    #     ),
    # }
    
    return reward_dict

def compute_success(env: ManagerBasedRLEnv) -> torch.Tensor:
    """
    Standardized success check. Automatically finds the EE index 
    using the body name from the robot configuration.
    """
    # 1. Get Target
    target_pos = env.command_manager.get_command("ee_pose")[:, :3]
    
    # 2. Dynamic EE Indexing
    # Instead of hardcoding '0', we find the index of 'panda_hand' or 'ee_link'
    robot = env.scene["robot"]
    
    # This matches the 'ee_body_name' passed in from reach.yaml
    # We use a simple search or pass it through the env_cfg
    ee_name = env.cfg.robot_ee_body_name # We'll ensure this is set in get_reward_cfg
    ee_index, _ = robot.find_bodies(ee_name)
    
    # 3. Get World Position of that specific index
    ee_pos = robot.data.body_pos_w[:, ee_index[0]] 
    
    # 4. Calculate Distance and Return
    distance = torch.norm(target_pos - ee_pos, dim=-1)
    return (distance < 0.05).float()